import React from 'react'
import { css } from '@linaria/core'
import { ResponsiveProvider } from '../responsive'
import { GridStart } from '../grid'

const flexCss = css`
  display: flex;
  flex: 1;
  flex-direction: column;
  min-height: 0;
  overscroll-behavior: contain; /* Prevents scroll chaining on mobile (FRONTIER-1772, FRONTIER-3177) */
`

export default function FullPageOverlayContent({ children }) {
  return (
    <ResponsiveProvider className={flexCss}>
      <GridStart className={flexCss} style={{ overflowY: 'auto' }}>
        {children}
      </GridStart>
    </ResponsiveProvider>
  )
}

FullPageOverlayContent.propTypes = {}
