import React from 'react'
import { Link } from '@fs/zion-router-base'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'
import Ellipsis from '../ellipsis'
import { textAcss } from '../typography/typographyStyles'

const breadcrumbsCss = css`
  display: flex;
  gap: 12px;

  & > :first-child {
    /* First breadcrumb should shrink ahead of the last one */
    flex-shrink: 1000;
  }

  & > :last-child {
    /* Last breadcrumb should shrink only when necessary. */
    flex-shrink: 1;
    /* Try to take up a larger chunk of space. */
    flex-basis: 100%;
    /* But don't take up more than is needed, (for when the last breadcrumb is small) */
    max-width: fit-content;
  }
`

const crumbCss = css`
  list-style: none;
  display: inline-flex;
  margin: 0;
  padding: 0;
  /* We want this to shrink all the way before the first and last crumbs */
  flex-shrink: 10000000;
  gap: 4px;
  min-width: 2ch;

  & > :first-child {
    /* This will show at least one dot in the ellipsis */
    min-width: 1.5ch;
    /* Needed to make Ellipsis work */
    display: block;
  }

  & > :nth-child(2) {
    flex-shrink: 0;
  }
`

function Crumb({ text, to, lineClamp, lastOne, ...crumb }) {
  const Wrapper = lastOne ? 'span' : Link
  const wrapperProps = lastOne ? { 'aria-current': 'page' } : { wayfinding: true, to: to || '#', ...crumb }
  return (
    <li className={crumbCss}>
      <Ellipsis as={Wrapper} lineClamp={lastOne ? lineClamp : undefined} className={crumbCss} {...wrapperProps}>
        {text}
      </Ellipsis>
      <span aria-hidden>{!lastOne && '›'}</span>
    </li>
  )
}

export default function Breadcrumbs({ breadcrumbs, lineClamp = 1 }) {
  if (!breadcrumbs?.length) return null

  return (
    <nav className={textAcss}>
      <ol className={breadcrumbsCss}>
        {breadcrumbs.map((crumb, index) => (
          <Crumb
            key={crumb.key || crumb.id || crumb.text + crumb.to}
            {...crumb}
            lineClamp={lineClamp}
            lastOne={index + 1 === breadcrumbs.length}
          />
        ))}
      </ol>
    </nav>
  )
}

Breadcrumbs.propTypes = {
  /** The list of breadcrumbs to show. Objects passed to the Link component. Text prop for children. */
  breadcrumbs: PropTypes.arrayOf(
    PropTypes.shape({
      /** Text for the breadcrumb */
      text: PropTypes.string,

      /** Path to the route. Example: to="/frontier/app/react". See https://reacttraining.com/react-router/web/api/Link for all options. */
      to: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.object]),

      /** For using Link outside of the Router. This prop is not needed for full urls. */
      external: PropTypes.bool,

      /** Action you'd like to see for this link on the analytics dashboard */
      action: PropTypes.string,

      /** If specified, and analytics is enabled for the react app, then analytics click metrics will be sent. The metrics will contain the specified value, which will be available in analytics reports.  */
      linkName: PropTypes.string,

      /** Optional way to also add an onclick to your link */
      onClick: PropTypes.func,

      /** If true this will prevent the page from scrolling to the top when clicked. Only works on internal links. */
      noScrollTop: PropTypes.bool,
    })
  ),

  /** The number of lines to clamp the last breadcrumb to. Defaults to 1. */
  lineClamp: PropTypes.number,
}
