import React, { useRef } from 'react'
import PropTypes from 'prop-types'
import { css, cx } from '@linaria/core'
import { sanitizeProps, useRandomId } from '@fs/zion-frontend-friends'
import { useBodyScrollLock } from '@fs/zion-react-utils'
import { colors } from '../theme'
import Overlay, { useOnClose } from '../overlay'
import Portal from '../portal'
import OpenCloseAnimation from '../open-close-animation'
import useEscHandler from '../use-esc-handler'
import useFocusLock from '../use-focus-lock'
import useAutoFocus from '../use-auto-focus'
import useClickAway from '../use-click-away'
import { InfoSheetProvider } from '../info-sheet/InfoSheetProvider'
import { PopperModifiersContext, defaultModifierCreator } from '../popper/PopperContext'
import FullPageOverlayHeader from './FullPageOverlayHeader'
import FullPageOverlayContent from './FullPageOverlayContent'
import { LayoutBandContext } from '../layout-band/LayoutBand'
import Scrim from '../scrim'
import { fitContentAreaCss } from '../scrim/Scrim'
import MarginBox from '../margin-box'
import { getOverlayHeader } from '../use-auto-focus/useAutoFocus'

const overlayCss = css`
  outline: none;
  z-index: 2; /* Create a stacking context, so all things inside this overlay will be contained (and on top of the main ui) */
  width: 100%;
  height: 100%;
`

const fullPageOverlayCss = css`
  background: ${colors.gray00};
  display: flex;
  flex-direction: column;
`

const footerCss = css`
  border-top: 1px solid ${colors.gray10};
`

const animStyles = {
  openStyles: {
    opacity: 1,
    config: {
      tension: 250,
    },
  },
  closeStyles: {
    opacity: 0,
    config: {
      tension: 300,
    },
  },
  derivedStyles: {
    transform: [['opacity'], (opacity) => `scale(${0.75 + opacity.toFixed(2) * 0.25})`],
  },
}

export default function FullPageOverlay({
  actions,
  'aria-label': ariaLabel,
  breadcrumbs = [],
  children,
  nav,
  showClose = true,
  subtitle,
  title,
  id,
  onClose,
  footer,
  focusRef,

  // From useOverlay()
  close,
  open,
  handleClick,
  handleOpen,
  targetRef,
  focusBackRef,
  handleTransitioned,
  isOpen,
  transitioning,
  editable,
  ...props
}) {
  const overlayRef = useRef(null)
  const portalRef = useRef()
  const randomId = useRandomId(id)
  const labelledById = `${randomId}-dialog-label`
  const describedById = `${randomId}-dialog-description`

  const ariaProps = {}
  if (ariaLabel) {
    ariaProps['aria-label'] = ariaLabel
  } else {
    ariaProps['aria-labelledby'] = labelledById
    ariaProps['aria-describedby'] = describedById
  }

  // onClose handler
  useOnClose({
    isOpen,
    transitioning,
    onClose,
  })

  // Close on escape key
  useEscHandler({
    handler: close,
    enabled: isOpen,
  })

  // Lock body scrolling when open
  useBodyScrollLock(isOpen, overlayRef)

  useFocusLock({
    enabled: isOpen,
    containerRef: portalRef,
  })

  useAutoFocus({
    isOpen,
    enabled: true,
    focusRef,
    containerRef: overlayRef,
    whatToFocusInContainer: getOverlayHeader,
  })

  // prevent from closing if spawned from a click-away overlay - cannot use useCancelOverlay on mousedown because full page overlay may spawn a quick glance overlay or similar (such as in RelationshipViewer) and putting that on a mousedown will make it so they never close.
  useClickAway({
    enabled: isOpen,
    contentRef: overlayRef,
    handler: () => {},
  })

  if (!isOpen && !transitioning) return null
  return (
    <Portal ref={portalRef}>
      <PopperModifiersContext.Provider value={defaultModifierCreator}>
        <Scrim isOpen={isOpen} />
        <Overlay
          className={overlayCss}
          ref={overlayRef}
          {...sanitizeProps(props)}
          {...ariaProps}
          z={0}
          borderRadius={0}
        >
          <OpenCloseAnimation
            onOpenFinished={handleTransitioned}
            onCloseFinished={handleTransitioned}
            isOpen={isOpen}
            className={cx(fitContentAreaCss, fullPageOverlayCss)}
            {...animStyles}
          >
            <FullPageOverlayHeader
              showClose={showClose}
              nav={nav}
              breadcrumbs={breadcrumbs}
              title={title}
              subtitle={subtitle}
              actions={actions}
              labelledById={labelledById}
              close={close}
            />
            <InfoSheetProvider inFullPageOverlay>
              <FullPageOverlayContent>
                <LayoutBandContext.Provider value={false}>{children}</LayoutBandContext.Provider>
              </FullPageOverlayContent>
              {footer && (
                <MarginBox as="footer" marginX="sm" marginY="xs" className={footerCss}>
                  {footer}
                </MarginBox>
              )}
            </InfoSheetProvider>
          </OpenCloseAnimation>
        </Overlay>
      </PopperModifiersContext.Provider>
    </Portal>
  )
}

const DomElement = typeof Element === 'undefined' ? () => {} : Element

FullPageOverlay.propTypes = {
  /** Props for all the action buttons. The first item is expecting a regular button, set it to null if you don't want it. */
  actions: PropTypes.arrayOf(
    PropTypes.shape({
      /** Whether the button is disabled */
      disabled: PropTypes.bool,

      /** The Icon to display in the button */
      Icon: PropTypes.elementType,

      /** Direction the icon should face - See zion-icon for more information */
      iconDirection: PropTypes.oneOf(['up', 'down', 'forward', 'backward']),

      /** Reflection of the icon - See zion-icon for more information */
      iconReflect: PropTypes.oneOf(['horizontal', 'vertical']),

      /** The aria-label/list item label to apply to the button */
      label: PropTypes.string.isRequired,

      /** Click handler for when the button is clicked */
      onClick: PropTypes.func,

      /** Whether the button moves into the overflow. Can only have one of the first four Button/IconButtons stay in the header */
      pinned: PropTypes.bool,

      /** Only supported on the first button. Defaults to `low` */
      emphasis: PropTypes.oneOf(['inline', 'low', 'medium', 'high', 'destroy', 'billboard']),
    })
  ),

  /** Defaults to the title. Only specify if you want something else. */
  'aria-label': PropTypes.string,

  /** The list of breadcrumbs to show. Objects passed to the Link component. Text prop for children. */
  breadcrumbs: PropTypes.arrayOf(
    PropTypes.shape({
      /** Text for the breadcrumb */
      text: PropTypes.string,
      /** URL for the breadcrumb */
      to: PropTypes.oneOfType([PropTypes.string, PropTypes.object]),
    })
  ),

  // /** Handler for the Help button. This may not be available in the future once HelpOverlay is integrated */
  // onHelpClick: PropTypes.func.isRequired,

  nav: PropTypes.shape({
    /** The props for the next IconButton */
    next: PropTypes.shape({
      /** Whether the button is disabled */
      disabled: PropTypes.bool,
      /** Click handler for when the button is clicked */
      onClick: PropTypes.func.isRequired,
    }),
    /** The props for the previous IconButton */
    previous: PropTypes.shape({
      /** Whether the button is disabled */
      disabled: PropTypes.bool,
      /** Click handler for when the button is clicked */
      onClick: PropTypes.func,
    }),
  }),

  /** Allows the caller to hide the back/close button */
  showClose: PropTypes.bool,

  /** The text to show as the title for the FullPageOverlay */
  title: PropTypes.string.isRequired,

  /** Content to go inside the FullPageOverlay's footer */
  footer: PropTypes.node,

  /** If you want the overlay to focus on something specific, pass a ref to it here. Must be a focusable element. */
  focusRef: PropTypes.shape({ current: PropTypes.instanceOf(DomElement) }),

  /** Handler fired whenever the dialog is closed. Fires no matter how the dialog is closed. */
  onClose: PropTypes.func,

  /** REQUIRED: Dialog Overlay needs all the props provided from the useOverlay hook in order to work */
  '{...useOverlay()}': PropTypes.object,
}
