import type { State, Action } from './types'

export const initialState: State = {
  initialZoomPan: undefined,
  currentPoint: undefined,
  onClickableElement: false,
  onDraggableElement: false,
  gestureType: null,
  drawing: false,
  wasDragged: false,
}

export const gestureReducer = (state: State, action: Action): State => {
  const { type, gestureType, point, onClickableElement, onDraggableElement } = action
  const { gestureType: currentGestureType } = state
  switch (type) {
    case 'POINT_DOWN':
      if (currentGestureType && currentGestureType !== gestureType) return state
      return {
        ...state,
        startPoint: point,
        currentPoint: undefined,
        wasDragged: false,
        gestureType,
        initialZoomPan: action.zoomPan,
        onClickableElement,
        onDraggableElement,
      }

    case 'POINT_MOVE': {
      const { startPoint } = state
      if (gestureType !== currentGestureType || state.onDraggableElement) return state
      let wasDragged = false

      // ZIONUI-1515 - We want to make sure wasDragged doesn't get set when wheel events happen
      if (gestureType !== 'WHEEL') {
        const deltaX = point.viewX - startPoint!.viewX // We know it's defined here.
        const deltaY = point.viewY - startPoint!.viewY // We know it's defined here.
        const delta = Math.hypot(deltaX, deltaY)
        if (delta > 3) wasDragged = true
      }
      return { ...state, wasDragged, currentPoint: point }
    }

    case 'POINT_UP':
      if (gestureType !== currentGestureType) return state
      return { ...state, currentPoint: point, initialZoomPan: undefined, gestureType: null }

    default: {
      // we are doing an exhaustive check to make sure we don't miss a case
      const exhaustiveCheck: never = action
      throw new Error(`Unsupported Action: ${JSON.stringify(exhaustiveCheck)}`)
    }
  }
}
