import React from 'react'
import { ArrowCaret } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { IconButton } from '../buttons/icon-button'
import { useContainerWidth } from '../responsive'
import Row from '../row'

export default function Nav({ nav }) {
  const atWidth = useContainerWidth()
  const [t] = useTranslation()
  const showNav = Boolean(nav)
  const defaultNav = nav ?? { previous: {}, next: {} }
  let { previous, next } = defaultNav
  previous = previous ?? {}
  next = next ?? {}
  return (
    showNav &&
    atWidth({
      default: null,
      lg: (
        <Row gutters="md" alignY="middle">
          <IconButton
            Icon={ArrowCaret}
            iconDirection="backward"
            title={t('common-ui:previous.action', 'Previous')}
            onClick={previous.onClick}
            disabled={previous.disabled}
            color="gray"
          />
          <IconButton
            Icon={ArrowCaret}
            title={t('common-ui:next.action', 'Next')}
            onClick={next.onClick}
            disabled={next.disabled}
            color="gray"
          />
        </Row>
      ),
    })
  )
}
