import React, { useMemo } from 'react'
import { MenuMore } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { useContainerWidth, usePageWidth } from '../responsive'
import { Button } from '../buttons'
import { IconButton } from '../buttons/icon-button'
import { MenuOverlay } from '../menu-overlay'
import { ListItem } from '../list'
import Row from '../row'

const DEFAULT_ACTIONS = []
export default function Actions({ actions = DEFAULT_ACTIONS, helpActionUrl, ...props }) {
  const atWidth = useContainerWidth()
  const isMdBreakpoint = usePageWidth()({ md: true })
  const [t] = useTranslation()
  const MAX_HEADER_BUTTONS = 4
  const MAX_PINNED_ACTIONS = 2
  const clonedActions = [...(Array.isArray(actions) ? actions : [])] // some people want to pass in null for actions. They should just use undefined instead, but we want to be robust
  const numberPinnable = MAX_HEADER_BUTTONS <= clonedActions.length ? MAX_HEADER_BUTTONS : clonedActions.length
  const pinnableActions = clonedActions.slice(0, numberPinnable)

  // Only two actions in the first 4 actions are allowed to be pinned as they are already visible in the header
  const pinnedActions = pinnableActions
    .filter((action) => Boolean(action) && action.pinned)
    .slice(0, MAX_PINNED_ACTIONS)

  let unPinnedActions = [...clonedActions]
  const showPinnedActions = useMemo(
    () => !isMdBreakpoint && pinnedActions.length > 0,
    [isMdBreakpoint, pinnedActions.length]
  )

  if (showPinnedActions) {
    const pinnedIndexes = pinnedActions.map((action) => clonedActions.indexOf(action))
    if (!pinnedIndexes.includes[0]) {
      // remove the pinned action Button
      unPinnedActions = clonedActions.map((action, i) => {
        if (i === 0 && action?.pinned) {
          return null
        }
        return action
      })
    } else {
      // remove the pinned action IconButton
      unPinnedActions = clonedActions.filter((action) => !action.pinned)
    }
  }

  // Removes prop from pinned actions not needed for IconButton
  const sanitizePinnedAction = (action) => {
    const clonedAction = { ...action }
    if (clonedAction.pinned) {
      delete clonedAction.pinned
    }
    return clonedAction
  }

  // display a limited amount of headerActions based on container width
  const headerActions = unPinnedActions.filter((action, i) => {
    return atWidth({
      default: false,
      sm: i === 0,
      md: i < MAX_HEADER_BUTTONS - 1,
      lg: i < MAX_HEADER_BUTTONS,
    })
  })

  // put any actions not in headerActions or pinnedActions into the overflow menu
  // ListItem takes slightly different props so we have to map them
  const overflowActions = unPinnedActions
    .filter((action) => Boolean(action) && !headerActions.includes(action) && !pinnedActions.includes(action))
    .map((action) => {
      const clonedAction = { ...action }
      if (clonedAction.Icon) {
        clonedAction.startElement = <ListItem.Icon Icon={clonedAction.Icon} />
        delete clonedAction.Icon
      }
      return sanitizePinnedAction(clonedAction)
    })

  return (
    <Row alignY="middle" gutters="sm" {...props}>
      {headerActions.map((action, i) => {
        if (i === 0 || !action?.Icon) {
          return (
            action && (
              <Button
                key={action.label}
                onClick={action.onClick}
                Icon={null}
                disabled={action.disabled}
                emphasis={action.emphasis}
                color="gray"
              >
                {action.label}
              </Button>
            )
          )
        }
        return (
          action && (
            <IconButton key={action.label} title={action.label} color="gray" {...sanitizePinnedAction(action)} />
          )
        )
      })}

      {showPinnedActions &&
        pinnedActions.map((action) => {
          return <IconButton key={action.label} title={action.label} color="gray" {...sanitizePinnedAction(action)} />
        })}

      {overflowActions.length > 0 && (
        <MenuOverlay
          inline={false}
          menuButton={<IconButton title={t('common-ui:menu.label', 'Menu')} Icon={MenuMore} color="gray" />}
        >
          {overflowActions.map((action) => (
            <ListItem key={action.label} primaryText={action.label} {...action} />
          ))}
        </MenuOverlay>
      )}
    </Row>
  )
}
