import React from 'react'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import { boolAttr } from '@fs/zion-frontend-friends'
import { Arrow } from '@fs/zion-icon'
import { H2, Subheading } from '../typography'
import Breadcrumbs from '../breadcrumbs'
import Actions from './Actions'
import Nav from './Nav'
import Ellipsis from '../ellipsis'
import { colors } from '../theme'
import { useContainerWidth, usePageWidth } from '../responsive'
import MarginBox from '../margin-box'
import Row from '../row'
import { IconButton } from '../buttons'
import { Cell } from '../grid'

const headerCss = css`
  border-bottom: 1px solid ${colors.gray10};

  // Add focus visible state to the header when the overlay is first opened (ACCESSIBLE-246)
  [data-overlay-header] {
    outline: none;

    &:focus-visible {
      outline: 2px solid ${colors.gray70};
      outline-offset: 2px;
      border-radius: 4px;
    }
  }
`

const headerItemCss = css`
  &[data-breadcrumbs] {
    padding-top: 16px;
  }
`

export default function OverlayHeader({ showClose, nav, breadcrumbs, title, subtitle, actions, labelledById, close }) {
  const [t] = useTranslation()
  const isSmBreakpoint = usePageWidth()({ sm: true })
  const atWidth = useContainerWidth()
  const showBreadcrumbs = isSmBreakpoint && !!breadcrumbs?.length
  return (
    <MarginBox as="header" className={headerCss} marginX="sm" marginY="nano">
      <Row alignY="middle" gutters="sm">
        {(showClose || nav) && (
          <Row gutters="lg" alignY="middle" className={headerItemCss} data-breadcrumbs={boolAttr(showBreadcrumbs)}>
            {showClose && (
              <IconButton
                title={t('common-ui:close.action', 'Close')}
                Icon={Arrow}
                iconDirection="backward"
                onClick={close}
                color="gray"
              />
            )}
            <Nav nav={nav} />
          </Row>
        )}
        <Cell growX>
          {atWidth({
            default: null,
            md: <Breadcrumbs breadcrumbs={breadcrumbs} />,
          })}
          <div
            // We focus the header for better accessibility. We have tested this with real blind users.
            // wrapping the H2 in an extra div so the screen readers will announce the subtitle as well
            tabIndex={-1}
            data-overlay-header
            role="group"
          >
            <H2 size="H5" id={labelledById}>
              <Ellipsis>{title}</Ellipsis>
              <Subheading>
                <Ellipsis>{subtitle}</Ellipsis>
              </Subheading>
            </H2>
          </div>
        </Cell>
        <Actions noShrinkX className={headerItemCss} data-breadcrumbs={boolAttr(showBreadcrumbs)} actions={actions} />
      </Row>
    </MarginBox>
  )
}
